	if ret.isEmpty() {
		return
	}

	argNames := map[string]struct{}{}
	for _, pair := range arg.Pairs() {
		argNames[pair.Name] = struct{}{}
	}

	if _, found := argNames[ret.Name]; !found {
		return
	}

	base := ret.Name
	for i := 2; ; i++ {
		name := fmt.Sprintf("%s_%d", base, i)
		if _, found := argNames[name]; !found {
			ret.Name = name
			return
		}
	}
}

